22	export function generateQuote(items: Item[], customer: Customer): { basePremium: number } {
23	  const nonCursedCountsByType: Record<string, number> = {};
24	  let cursedPremium = 0;
25	  let enchantmentSurcharge = 0;
26	
27	  for (const item of items) {
28	    const itemBasePremium = BASE_PREMIUMS[item.type];
29	    if (item.cursed) {
30	      cursedPremium += itemBasePremium * 1.5;
31	    } else {
32	      nonCursedCountsByType[item.type] = (nonCursedCountsByType[item.type] ?? 0) + 1;
33	      if (item.enchantment !== undefined && item.enchantment >= 5) {
34	        enchantmentSurcharge += itemBasePremium * 0.3;
35	      }
36	    }
37	  }
38	
39	  let basePremium = cursedPremium;
40	  for (const [type, count] of Object.entries(nonCursedCountsByType)) {
41	    if (count === 3) {
42	      basePremium += BLOCK_PRICE_FOR_3_ALIKE;
43	    } else {
44	      basePremium += count * BASE_PREMIUMS[type];
45	    }
46	  }
47	  basePremium += enchantmentSurcharge;
48	
49	  return { basePremium };
50	}
